from ecommerce_app.models import KYC
from ecommerce_app.serializers import KYCSerializer

if request.user.is_authenticated:
    action = request.data.get('action') # 'create', 'edit', 'get'

    if action == 'create':
        if KYC.objects.filter(user=request.user).exists():
             response_data['status_code'] = 400
             response_data['message'] = "KYC already exists"
        else:
            # Serializer handles file uploads if passed in request.FILES / request.data
            serializer = KYCSerializer(data=request.data)
            if serializer.is_valid():
                serializer.save(user=request.user)
                response_data['status_code'] = 201
                response_data['message'] = "KYC submitted"
                response_data['data'] = serializer.data
            else:
                response_data['status_code'] = 400
                response_data['message'] = str(serializer.errors)

    elif action == 'edit':
        try:
            kyc = KYC.objects.get(user=request.user)
            if kyc.status == 'verified':
                 response_data['status_code'] = 400
                 response_data['message'] = "Cannot edit verified KYC"
            else:
                # partial=True allows creating/updating with subset of fields
                serializer = KYCSerializer(kyc, data=request.data, partial=True)
                if serializer.is_valid():
                    serializer.save()
                    response_data['status_code'] = 200
                    response_data['message'] = "KYC updated"
                    response_data['data'] = serializer.data
                else:
                    response_data['status_code'] = 400
                    response_data['message'] = str(serializer.errors)
        except KYC.DoesNotExist:
             response_data['status_code'] = 404
             response_data['message'] = "KYC not found"

    elif action == 'get' or action is None:
        try:
            kyc = KYC.objects.get(user=request.user)
            serializer = KYCSerializer(kyc)
            response_data['status_code'] = 200
            response_data['data'] = serializer.data
            response_data['message'] = "KYC details fetched"
        except KYC.DoesNotExist:
             response_data['status_code'] = 404
             response_data['message'] = "KYC not found"

    else:
        response_data['status_code'] = 400
        response_data['message'] = "Invalid action"
else:
    response_data['status_code'] = 401
    response_data['message'] = "Unauthorized"

from ecommerce_app.models import Wallet, Transaction
from ecommerce_app.serializers import TransactionSerializer

if request.user.is_authenticated:
    try:
        wallet, _ = Wallet.objects.get_or_create(user=request.user)
        transactions = Transaction.objects.filter(user=request.user).order_by('-created_at')
        serializer = TransactionSerializer(transactions, many=True)

        response_data['status_code'] = 200
        response_data['message'] = "Wallet details fetched"
        response_data['data'] = {
            "current_balance": float(wallet.current_balance),
            "transactions": serializer.data
        }
    except Exception as e:
        response_data['status_code'] = 500
        response_data['message'] = str(e)
else:
    response_data['status_code'] = 401
    response_data['message'] = "Unauthorized"

from ecommerce_app.models import WithdrawalRequest, Wallet, KYC
from decimal import Decimal

if request.user.is_authenticated:
    amount = request.data.get('amount')

    if amount:
        try:
            amount_decimal = Decimal(str(amount))
            if amount_decimal <= 0:
                 response_data['status_code'] = 400
                 response_data['message'] = "Amount must be positive"
            else:
                # 1. Check KYC Status
                try:
                    kyc = KYC.objects.get(user=request.user)
                    if kyc.status != 'verified':
                        response_data['status_code'] = 400
                        response_data['message'] = "KYC not verified. Please complete KYC checks."
                    else:
                        # 2. Check Wallet Balance
                        wallet, _ = Wallet.objects.get_or_create(user=request.user)

                        # Consider pending withdrawals? 
                        # Logic requested: "wallet has enough fund or not".
                        # Ideally: available = balance - pending_withdrawals
                        # Let's check pending first to be safer, if possible.
                        # pending_withdrawals = WithdrawalRequest.objects.filter(user=request.user, status='pending').aggregate(sum=Sum('amount'))['sum'] or 0

                        if wallet.current_balance >= amount_decimal:
                             # Create Request
                             withdrawal = WithdrawalRequest.objects.create(
                                 user=request.user,
                                 amount=amount_decimal,
                                 status='pending'
                             )
                             response_data['status_code'] = 201
                             response_data['message'] = "Withdrawal request submitted successfully"
                             response_data['request_id'] = withdrawal.id
                        else:
                             response_data['status_code'] = 400
                             response_data['message'] = "Insufficient Wallet Balance"

                except KYC.DoesNotExist:
                     response_data['status_code'] = 400
                     response_data['message'] = "KYC not found. Please submit KYC."

        except Exception as e:
             response_data['status_code'] = 500
             response_data['message'] = str(e)
    else:
        response_data['status_code'] = 400
        response_data['message'] = "Amount required"
else:
    response_data['status_code'] = 401
    response_data['message'] = "Unauthorized"
